UPDATE agent_task
SET title = #{title},
    updated_at = CURRENT_TIMESTAMP
WHERE id = #{id}
  AND user_id = #{userId}

UPDATE agent_task
SET folder_id = #{folderId},
    updated_at = CURRENT_TIMESTAMP
WHERE id = #{id}
  AND user_id = #{userId}

UPDATE agent_task
SET folder_id = NULL,
    updated_at = CURRENT_TIMESTAMP
WHERE folder_id = #{folderId}
  AND user_id = #{userId}
